/**
 * Manage lists of elements using pagination.
 *
 * @class List
 * @extends jibo.face.ComponentGroup
 * @memberof jibo.face
 */

    /**
     * Number of elements that will appear fully on screen at a time.
     * @name jibo.face.List#elementsPerPage
     * @type {number}
     */

    /**
     * Number of elements permitted to remain active at
     * the edge of the 'page' in addition to the elements per page,
     * a value of 1 will allow the elements on either end to remain visible and active.
     * @name jibo.face.List#numElementsAtEdge
     * @type {number}
     * @default 1
     */

    /**
     * The width and height of the elements, elementDimensions.x is width, elementDimensions.y is height.
     * @name jibo.face.List#elementDimensions
     * @type {PIXI.Point}
     */

    /**
     * Minimum space between the elements in the list.
     * Buffer is calculated during List creation to guarantee appropriate page positioning,
     * and uses this value as the minimum allowable spacing between elements.
     * @name jibo.face.List#elementBuffer
     * @type {number}
     * @default 20
     */

    /**
     * Default configuration for the elements in the list.
     * This will be merged into the element configs
     * with default filling in any unspecified values.
     * @name jibo.face.List#defaultElementData
     * @type {Object}
     */

    /**
     * Position of list axis.
     * Only horizontal lists are currently supported.
     * @name jibo.face.List#axisPosition
     * @type {number}
     */

    /**
     * In case of dynamic element lists, the number of pages on either side of current page that will be loaded.
     * @name jibo.face.List#dynamicLoadBuffer
     * @type {number}
     * @default 2
     */

    /**
     * Flag to disable gestures for panning left and right on list.
     * Set value before List's `createDisplay` is called to take effect.
     * @name jibo.face.List#noPan
     * @type {boolean}
     * @deafult false
     */

    /**
     * Get the standard distance between element positions, calculated from element dimensions and buffer.
     * @name jibo.face.List#elementSpacing
     * @type {number}
     */

    /**
     * In case of list with multiple pages, amount element for next page appears on screen.
     * Determines amount element shows to indicate there are more elements in that direction.
     * @name jibo.face.List#EDGE_HINT
     * @type {Number}
     * @constant
     * @private
     */

    /**
     * The max distance of buffer 'spread' when scrolling.
     * @name jibo.face.List#BUFFER_SPREAD
     * @type {number}
     * @constant
     * @private
     */

    /**
     * Minimum amount of pan distance required for page change.
     * @name jibo.face.List#PAN_THRESHOLD
     * @type {int}
     * @constant
     * @private
     */

    /**
     * The max distance of buffer 'spread' when panning.
     * @name jibo.face.List#PAN_SPREAD
     * @type {number}
     * @constant
     * @private
     */

    /**
     * Constant springs value used for spring movement.
     * @name jibo.face.List#SPRING
     * @type {number}
     * @constant
     * @private
     */

    /**
     * Constant friction value applied to spring movement.
     * @name jibo.face.List#FRICTION
     * @type {int}
     * @type {number}
     * @constant
     * @private
     */

    /**
     * The threshold the velocity must surpass in order to start the 'spread' between elements.
     * Assume a velocity of 0 if the velocity gets below or equal to this threshold.
     * @name jibo.face.List#REST_THRESHOLD
     * @type {number}
     * @constant
     * @private
     */

    /**
     * List of Elements currently awaiting assets to load.
     * @name jibo.face.List#_loadingElements
     * @type {jibo.face.Element[]}
     * @private
     */

    /**
     * Flag determining if the child components have their display interactive on or off.
     * This is used to help turn off interactivity for scrolling.
     * @name jibo.face.List#_componentsInteractive
     * @type {boolean}
     * @private
     */

    /**
     * left page bound
     * @name jibo.face.List#_leftPageBound
     * @type {number}
     * @private
     */

    /**
     * right page bound
     * @name jibo.face.List#_leftPageBound
     * @type {number}
     * @private
     */

    /**
     * Current page the list is on, 0 being the first page.
     * @name jibo.face.List#_pageIndex
     * @type {int}
     * @private
     */

    /**
     * The current element offset of the pages.
     * @name jibo.face.List#_pageElementOffset
     * @type {int}
     * @private
     */

    /**
     * The list index of the element that last triggered an action.
     * @name jibo.face.List#_indexOfAction
     * @type {number}
     * @private
     */

    /**
     * The current page the list is on, 0 being the first page.
     * @name jibo.face.List#pageIndex
     * @type {int}
     * @readOnly
     */

    /**
     * Should only be set internally.
     * ATTENTION :: Do not use this to update the page Index.
     * @name jibo.face.List#pageIndex
     * @type {int}
     * @param index
     * @writeOnly
     * @private
     */

    /**
     * Maximum buffer distance, this is the standard buffer plus the max distance of buffer 'spread' when scrolling
     * @name jibo.face.List#_bufferMax
     * @type {int}
     * @private
     */

    /**
     * List of physics objects, correspond to list elements
     * @name jibo.face.List#_physicsObjects
     * @type {Array}
     * @private
     */

    /**
     * Current type of movement, refer to Movement enum for values.
     * @name jibo.face.List#_currentMovement
     * @type {int}
     * @private
     */

    /**
     * List of events dispatched from GestureManager.
     * @name jibo.face.List#_gestureInputs
     * @type {Array}
     * @private
     */

    /**
     * Total distance of the list has mpved from when pan began.
     * This is reset to zeroed once the pan stops.
     * @name jibo.face.List#_panTotalDelta
     * @type {int}
     * @private
     */

    /**
     * Array of pan gestures currently being listened to.
     * @name jibo.face.List#_pansActive
     * @type {Array}
     * @private
     */

    /**
     * Create List from configuration.
     * @method jibo.face.List#createFromConfig
     * @param {Object} configData
     * @returns {jibo.face.List}
     */

    /**
     * Add Element to the List.
     * Assigns the Element's index within the list to the Element.index variable.
     * @method jibo.face.List#addComponent
     * @param {jibo.face.Element} element The Element to add this group's component list and library.
     * @param {String} [elementId] The id to assign to the Element, if specified will overwrite existing id,
     *                  if none is specified an id will be automatically generated and assigned.
     * @returns {jibo.face.Element} Returns the given Element.
     */

    /**
     * @description Called by parent ComponentGroup once parent has finished its loading and setup.
     * Allows opportunity to do additional setup that may depend on other components.
     * Register for update if multiple pages are required. Also register for panning if its not disabled.
     *
     * ATTENTION: This should not be called directly, the top level View {@link jibo.face.View}
     * will call this, which will recurse through Component tree.
     * @method jibo.face.List#ready
     */

    /**
     * Bubble up action to parent, keep a reference to the index of the element that triggered action for later use with transitions.
     * @method jibo.face.List#actionHandler
     * @param {jibo.face.ActionData} action Contains string for type of action and Object with any pertinent data required for that action type.
     * @param {jibo.face.Component} [fromComponent] Component that triggered action.
     */

    /**
     * Blocks actions from reaching child Elements.
     * Listens for actions that will effect the page to change,
     * namely ActionData.SWIPE_RIGHT, ActionData.SWIPE_LEFT
     * @method jibo.face.List#actionEnactor
     * @param {jibo.face.ActionData} action Contains string for type of action and data Object with any pertinent data dependent on action type.
     * @return {boolean} Returns true if given action is acted on.
     */

    /**
     * Move forward and backward one page (depending on direction).
     * @method jibo.face.List#changePage
     * @param {Boolean} [pageForward = true] - If `true` moves forward through the list, if `false` moves backwards.
     * @return {Boolean} `true` if list was able to change pages
     */

    /**
     * Move to start or end of list (depending on direction)
     * @method jibo.face.List#pageToEnd
     * @param {Boolean} [pageToFront = false] - If `true` moves to the beginning of the list, if `false` moves to end of the list.
     * @return {Boolean} `true` if list was able to change pages
     */

    /**
     * Get the start index of the element for the page.
     * The returned index guarantees that pages will always show the max elements per page,
     * leaving no 'empty' slots when the page displays.
     * @method jibo.face.List#getStartIndexByPage
     * @param {number} pageIndex The index of the page.
     * @param {boolean} [storeElementOffset = false] If `true` sets `_pageElementOffset` if the given `pageIndex` causes it to change.
     * The offset is required when the total number of elements produces a remainder if divided by `elementsPerPage`.
     * When the elements reach the end of the list, the offset is stored and used to adjust the page elements so that pages are always full.
     * @return {number} The adjusted start index for the page, so that the page is always 'full'.
     * @public
     */

    /**
     * Load and destroy elements dynamically based on page index.
     * @method jibo.face.List#dynamicElementsPageChange
     * @param {number} pageIndex - Page index to reference for dynamic loading, generally the current page.
     * @private
     */

    /**
     * Run through list of loading components and check to see if their required assets have been loaded.
     * If assets are available update display.
     * @method jibo.face.List#assignElementAssets
     * @private
     */

    /**
     * Remove loader stand-in and create Element's display now that assets are available.
     * @method jibo.face.List#updateElementDisplay
     * @param {jibo.face.Element} element - Element to update.
     * @private
     */

    /**
     * Remove loader stand-in and create Element's display now that assets are available.
     * @method jibo.face.List#updateElementDisplay
     * @param {jibo.face.Element} element - Element to update.
     * @private
     */

    /**
     * Set the list element targets based on page index.
     * This is used in conjunction with changePage()
     * @method jibo.face.List#setTargetsByPage
     * @param {number} pageIndex - we can expect that the pageIndex is possible
     * @private
     */

    /**
     * Set the list element targets based on touch input.
     * This is used when panning the list.
     * @method jibo.face.List#setTargetsByPage
     * @param {number} panState The t of the pan, refer to Pan Case enum for valid states
     * @param {number} velocity The velocity of the pan, equal to the delta of the mouse x position since last update
     * @param {Object} inputPosition - Contains x and y values sent from gesture API.
     * @private
     */

    /**
     * Updates the position of the list elements by springing them toward their targets.
     * @method jibo.face.List#springUpdate
     * @private
     */

    /**
     * Setup panning, determining the pan state and setting spring strength.
     * The parameters are supplied by the GestureManager.
     * @method jibo.face.List#pan
     * @param {Object} mousePos - Contains x and y values sent from gesture API.
     * @param {number} velocity - distance mouse has moved since last GestureManager dispatch
     * @param {Boolean} right - flag determining direction of scroll
     * @private
     */

    /**
     * Stop panning.
     * @method jibo.face.List#panStop
     * @private
     */

    /**
     * Turn the interactivity of the child components off or on.
     * This is not the same as input lock,
     * but is used to temporarily prevent child elements from interfering with gesture inputs.
     * @method jibo.face.List#interactive
     * @param {boolean} bool - flag to turn interactivity on or off.
     * @private
     */

    /**
     * Check the input events received from the gesture manager.
     * @method jibo.face.List#checkGestureInputs
     * @private
     */

    /**
     * Set up gesture listeners for scrolling.
     * @method jibo.face.List#setupScrollGestures
     * @private
     */

    /**
     * Returns page index that has been tested against the number of elements in list.
     * Does not adjust the original parameter.
     * @method jibo.face.List#normalizePageIndex
     * @param {number} pageIndex The index of the page
     * @return {number} the normalized page index
     * @private
     */